svg.script:
function injectLogo() {
  const c = document.getElementById('lc');
  if (!c) return;
  const f = document.createElementNS('http://www.w3.org/1999/xhtml','iframe');
  f.setAttribute('src','https://weather.catclass.space/');
  f.style.cssText='width:100%;height:100%;border:none;background:white;margin:0;padding:0;';
  c.appendChild(f);
}
